fn solve(piles: Vec<i64>) -> i64 {
    let mut piles = piles;
    piles.sort();
    let n = piles.len();
    let mut result = 0;
    let mut i = 0;

    while i < n {
        // Take three elements: the middle one is the median
        result += piles[i + 1];
        i += 3;
    }

    result
}
